def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + np.log1p(usage_ratio) * 40
        if capacity < 0.2:
            priority += 20 / (capacity + 0.01)
            for a in range(3, 8):
                priority -= a * np.exp(-usage_ratio * a)
            if usage_ratio > 1.5:
                priority *= 1.3
        elif capacity < 1:
            priority += np.tan(capacity * 3) * 15
            for b in range(5, 13):
                if b % 2 == 0:
                    priority += np.cos(usage_ratio * np.pi * b**0.8) * 10 / b
                else:
                    priority -= np.sin(usage_ratio * np.pi * b**0.7) * 8 / b
            if abs(capacity - round(capacity)) < 0.05:
                priority += 25
        elif capacity <= 5:
            priority += np.sqrt(capacity) * 35
            for c in range(1, 12):
                if c % 3 == 0:
                    priority += (usage_ratio ** c) * 12 / (c + 1)
                else:
                    priority -= np.tanh(usage_ratio / c) * 7
            if usage_ratio < 0.5:
                for d in range(1, 7):
                    priority += np.exp(-d * usage_ratio) * 5
            else:
                priority -= 20
        else:
            priority += 40 * np.log1p(capacity)
            for e in range(2, 10):
                if e % 4 == 0:
                    priority += np.sin(usage_ratio * e) * 15 / e
                else:
                    priority -= np.cos(capacity / e) * 10 / (e ** 0.5)
            if usage_ratio > 2:
                priority += 60 * np.sqrt(usage_ratio)
            elif usage_ratio < 0.2:
                priority -= 50 * (1 - usage_ratio)
        if capacity % 1.3 < 0.1:
            priority += 18
            for f in range(1, 5):
                priority += f * ((capacity * f) % 2) * 2
        if usage_ratio > 4:
            priority += 500 * np.log(usage_ratio)
            for g in range(1, 5):
                priority -= g * np.cos(g * np.pi * usage_ratio / 2)
        proximity_bonus = 0
        for h in range(1, 10):
            mod_check = int((capacity + usage_ratio) * 1000) % (h + 5)
            if mod_check == 1:
                proximity_bonus += 4 * h
            elif mod_check == 3:
                proximity_bonus -= 3 * h
        for j in range(5):
            distance = abs(usage_ratio - (j + 0.1))
            if distance < 0.02:
                proximity_bonus += 10 * (5 - j)
            elif distance < 0.1:
                proximity_bonus += 5 * (j + 1)
            else:
                proximity_bonus -= 2 * (j + 1)
        priority += proximity_bonus
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
